mapper.select:
SELECT a.chnl_id, a.chnl_nm, a.chnl_disp_nm, a.track_id, a.track_nm, f.artist_id reqArtistId, f.artist_nm reqArtsitNm, a.agency_id, b.album_id, e.artist_id, e.artist_nm, c.album_img_size size, CONCAT(c.album_img_url,'?updateDate=',UNIX_TIMESTAMP(c.update_dtime)) url, a.create_dtime, a.update_dtime, a.track_cnt trackCount, a.img_size, a.img_url, a.track_sn, a.renew_track_cnt, a.renew_dtime, a.trackCreateDtime, a.trackUpdateDtime, a.trackRenewDtime, a.rank FROM ( SELECT a.chnl_id, a.chnl_nm, a.chnl_disp_nm, a.renew_track_cnt, a.renew_dtime, a.track_id, a.track_nm, a.agency_id, a.album_id, a.create_dtime, a.update_dtime, a.track_cnt, a.track_sn, a.reprsnt_artist_id, a.img_size, a.img_url, a.trackCreateDtime trackCreateDtime, a.trackUpdateDtime trackUpdateDtime, a.trackRenewDtime trackRenewDtime, @prevChnlId:=a.chnl_id, @curRank:=IF(@prevChnlId = a.chnl_id,@curRank + 1,1) AS rank FROM ( SELECT a.chnl_id, a.chnl_disp_nm, a.renew_track_cnt, a.renew_dtime, a.chnl_nm, a.track_cnt, a.create_dtime, a.update_dtime, b.img_size, b.img_url, d.track_id, d.track_nm, d.agency_id, d.album_id, d.reprsnt_artist_id, d.create_dtime trackCreateDtime, d.update_dtime trackUpdateDtime, c.create_dtime trackRenewDtime, c.track_sn FROM tb_chnl a INNER JOIN tb_img_mang b ON a.chnl_id = b.img_content_id INNER JOIN tb_map_chnl_track c ON a.chnl_id = c.chnl_id INNER JOIN tb_track d ON c.track_id = d.track_id WHERE a.disp_status_type = 'Y' AND b.img_content_type = 'CHNL' AND b.os_type = #{osType} AND b.dfk_type = 'EVERY' AND a.chnl_id IN
#{channelId}
AND d.disp_status_yn = 'Y' ORDER BY FIELD(a.chnl_id,
#{channelId} ) , c.track_sn ASC ) a ) a LEFT OUTER JOIN ted_album b ON a.album_id = b.album_id LEFT OUTER JOIN tb_album_img c ON b.album_id = c.album_id LEFT OUTER JOIN ted_trackartist d ON a.track_id =d.track_id LEFT OUTER JOIN ted_artist e ON d.artist_id = e.artist_id LEFT OUTER JOIN ted_artist f ON f.artist_id = a.reprsnt_artist_id , (SELECT @curRank:=0, @prevChnlId:=0) r WHERE a.rank <= #{trackLimitSize}

SELECT chnl_id, prefer_genre_id, rank FROM ( SELECT a.chnl_id, a.prefer_genre_id, @prevChartId:=a.chart_id, @curRank:=IF(@prevChartId = a.chart_id, @curRank + 1, 1) AS rank FROM ( SELECT a.svc_genre_id, a.prefer_genre_id, b.chart_id, b.music_content_type, b.chart_nm, b.music_content_cnt, c.music_content_id chnl_id, c.disp_sn FROM ( SELECT DISTINCT svc_genre_id, prefer_genre_id FROM tb_map_prefer_genre_svc_genre WHERE prefer_genre_id IN
#{preferGenreId}
GROUP BY prefer_genre_id ORDER BY FIELD(prefer_genre_id,
#{preferGenreId}
) , disp_sn ) a INNER JOIN tb_chart b ON a.svc_genre_id = b.svc_content_id INNER JOIN tb_chart_music_content c ON b.chart_id = c.chart_id INNER JOIN tb_img_mang d ON c.music_content_id = d.img_content_id INNER JOIN tb_chnl e ON d.img_content_id = e.chnl_id WHERE b.chart_type = 'WEEKLY' AND b.svc_content_type = 'GENRE' AND b.music_content_type = 'CHNL' AND d.img_content_type = 'CHNL' AND d.dfk_type = 'EVERY' AND d.os_type = #{osType} AND d.img_disp_type = 'DEFAULT' AND e.disp_status_type = 'Y' GROUP BY chnl_id ORDER BY b.chart_id , c.disp_sn ) a,(SELECT @curRank:=0, @prevChartId:=0) r ) a WHERE rank <= 1
